import { useState, useRef } from 'react';
import {
    Box,
    Button,
    Typography,
    IconButton,
    Divider,
    Paper
} from '@mui/material';
import {
    Add as AddIcon,
    Delete as DeleteIcon,
    AddPhotoAlternate as AddPhotoIcon
} from '@mui/icons-material';
import PhotoBookPage from './PhotoBookPage';

const PhotoBookPages = ({ format, availablePhotos, pages, onPagesChange, onPhotosAdd }) => {
    const [selectedPhotos, setSelectedPhotos] = useState([]);
    const fileInputRef = useRef(null);

    const handleAddSpread = () => {
        // Добавляем разворот (две страницы)
        onPagesChange([
            ...pages,
            { 
                spreadId: pages.length / 2,
                leftPage: { photos: [] },
                rightPage: { photos: [] }
            }
        ]);
    };

    const handleDeleteSpread = (spreadIndex) => {
        const newPages = pages.filter((_, index) => index !== spreadIndex);
        onPagesChange(newPages);
    };

    const handleFileSelect = (event) => {
        const files = Array.from(event.target.files);
        if (files.length > 0) {
            onPhotosAdd(files);
        }
        // Очищаем input для возможности повторной загрузки тех же файлов
        event.target.value = '';
    };

    const handlePhotoAdd = (spreadIndex, isRightPage, position, photo) => {
        const newPages = [...pages];
        const spread = newPages[spreadIndex];
        if (spread) {
            const targetPage = isRightPage ? spread.rightPage : spread.leftPage;
            targetPage.photos = [
                ...targetPage.photos.filter(p => p.position !== position),
                { ...photo, position }
            ];
            onPagesChange(newPages);
            setSelectedPhotos(prev => [...prev, photo.id]);
        }
    };

    const handlePhotoRemove = (spreadIndex, isRightPage, position) => {
        const newPages = [...pages];
        const spread = newPages[spreadIndex];
        if (spread) {
            const targetPage = isRightPage ? spread.rightPage : spread.leftPage;
            const removedPhoto = targetPage.photos.find(p => p.position === position);
            if (removedPhoto) {
                setSelectedPhotos(prev => prev.filter(id => id !== removedPhoto.id));
            }
            targetPage.photos = targetPage.photos.filter(p => p.position !== position);
            onPagesChange(newPages);
        }
    };

    const handlePhotoEdit = (spreadIndex, isRightPage, position, editedPhoto) => {
        const newPages = [...pages];
        const spread = newPages[spreadIndex];
        if (spread) {
            const targetPage = isRightPage ? spread.rightPage : spread.leftPage;
            const photoIndex = targetPage.photos.findIndex(p => p.position === position);
            if (photoIndex !== -1) {
                targetPage.photos[photoIndex] = {
                    ...targetPage.photos[photoIndex],
                    ...editedPhoto
                };
                onPagesChange(newPages);
            }
        }
    };

    return (
        <Box sx={{ width: '100%', p: 2 }}>
            <Box sx={{ mb: 4 }}>
                <Typography variant="h5" gutterBottom align="center">
                    Создание страниц фотокниги
                </Typography>
                <Typography variant="subtitle1" color="text.secondary" gutterBottom align="center">
                    Перетащите фотографии на страницы
                </Typography>
            </Box>

            <Box sx={{ 
                display: 'flex', 
                flexDirection: 'column', 
                gap: 4,
                maxWidth: '100%',
                overflow: 'auto'
            }}>
                {pages.map((spread, spreadIndex) => {
                    // Рассчитываем размеры на основе пропорций формата
                    const maxWidth = 1000; // Максимальная ширина разворота
                    const maxHeight = 600; // Максимальная высота разворота

                    // Получаем размеры из формата
                    const formatWidth = format.dimensions?.width || 20;
                    const formatHeight = format.dimensions?.height || 20;

                    // Рассчитываем масштаб, сохраняя пропорции
                    const scale = Math.min(
                        maxWidth / (formatWidth * 2), // *2 для разворота
                        maxHeight / formatHeight
                    );

                    const pageWidth = formatWidth * scale;
                    const pageHeight = formatHeight * scale;

                    return (
                        <Paper 
                            key={spreadIndex}
                            elevation={3}
                            sx={{ 
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                p: 2,
                                position: 'relative'
                            }}
                        >
                            <Box sx={{ 
                                position: 'absolute',
                                top: 8,
                                right: 8,
                                zIndex: 1
                            }}>
                                <IconButton
                                    onClick={() => handleDeleteSpread(spreadIndex)}
                                    color="error"
                                    size="small"
                                >
                                    <DeleteIcon />
                                </IconButton>
                            </Box>

                            <Box sx={{ 
                                display: 'flex',
                                width: pageWidth * 2 + 40, // 40px для переплета
                                height: pageHeight,
                                bgcolor: 'background.paper',
                                boxShadow: 2
                            }}>
                                {/* Левая страница */}
                                <PhotoBookPage
                                    format={format}
                                    pageWidth={pageWidth}
                                    pageHeight={pageHeight}
                                    photos={spread.leftPage.photos}
                                    availablePhotos={availablePhotos.filter(
                                        photo => !selectedPhotos.includes(photo.id)
                                    )}
                                    onPhotoAdd={(position, photo) => 
                                        handlePhotoAdd(spreadIndex, false, position, photo)
                                    }
                                    onPhotoRemove={(position) => 
                                        handlePhotoRemove(spreadIndex, false, position)
                                    }
                                    onPhotoEdit={(position, photo) => 
                                        handlePhotoEdit(spreadIndex, false, position, photo)
                                    }
                                />

                                {/* Переплет */}
                                <Divider 
                                    orientation="vertical" 
                                    sx={{ 
                                        width: 40,
                                        bgcolor: 'grey.300',
                                        my: -2
                                    }} 
                                />

                                {/* Правая страница */}
                                <PhotoBookPage
                                    format={format}
                                    pageWidth={pageWidth}
                                    pageHeight={pageHeight}
                                    photos={spread.rightPage.photos}
                                    availablePhotos={availablePhotos.filter(
                                        photo => !selectedPhotos.includes(photo.id)
                                    )}
                                    onPhotoAdd={(position, photo) => 
                                        handlePhotoAdd(spreadIndex, true, position, photo)
                                    }
                                    onPhotoRemove={(position) => 
                                        handlePhotoRemove(spreadIndex, true, position)
                                    }
                                    onPhotoEdit={(position, photo) => 
                                        handlePhotoEdit(spreadIndex, true, position, photo)
                                    }
                                />
                            </Box>
                        </Paper>
                    );
                })}
            </Box>

            <Box sx={{ mt: 4, display: 'flex', justifyContent: 'center', gap: 2 }}>
                <Button
                    variant="contained"
                    startIcon={<AddIcon />}
                    onClick={handleAddSpread}
                >
                    Добавить разворот
                </Button>
                <input
                    type="file"
                    multiple
                    accept="image/*"
                    style={{ display: 'none' }}
                    ref={fileInputRef}
                    onChange={handleFileSelect}
                />
                <Button
                    variant="outlined"
                    startIcon={<AddPhotoIcon />}
                    onClick={() => fileInputRef.current?.click()}
                >
                    Добавить фотографии
                </Button>
            </Box>
        </Box>
    );
};

export default PhotoBookPages;
